import{_ as t,o,c as a,a5 as n}from"./chunks/framework.CU-GVwQ3.js";const u=JSON.parse('{"title":"ADR-002: Analysis Registries and Tree Structure","description":"","frontmatter":{},"headers":[],"relativePath":"adr/002-analysis-registries-and-tree-structure.md","filePath":"adr/002-analysis-registries-and-tree-structure.md"}'),s={name:"adr/002-analysis-registries-and-tree-structure.md"};function r(i,e,d,c,l,h){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="adr-002-analysis-registries-and-tree-structure" tabindex="-1">ADR-002: Analysis Registries and Tree Structure <a class="header-anchor" href="#adr-002-analysis-registries-and-tree-structure" aria-label="Permalink to &quot;ADR-002: Analysis Registries and Tree Structure&quot;">​</a></h1><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>Accepted</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The OpenAPI specification is represented as a tree of annotation objects rooted at <code>OpenApi</code>. Processors need to both query annotations by type (&quot;find all Schemas&quot;) and traverse structural relationships (&quot;what refs does this subtree contain&quot;). The system maintains two flat registries alongside the tree to support efficient queries.</p><h2 id="the-two-registries" tabindex="-1">The Two Registries <a class="header-anchor" href="#the-two-registries" aria-label="Permalink to &quot;The Two Registries&quot;">​</a></h2><h3 id="analysis-annotations-splobjectstorage" tabindex="-1"><code>$analysis-&gt;annotations</code> (SplObjectStorage) <a class="header-anchor" href="#analysis-annotations-splobjectstorage" aria-label="Permalink to &quot;`$analysis-&gt;annotations` (SplObjectStorage)&quot;">​</a></h3><p>A flat index of all annotations keyed by object identity, with Context as the attached value.</p><p><strong>Populated by:</strong> <code>Analysis::addAnnotation()</code>, which recursively registers the annotation and all its nested children at the time of the call.</p><p><strong>Read by:</strong></p><ul><li><code>getAnnotationsOfType()</code> — query all annotations of a given class (used by ~15 processors)</li><li>Direct iteration in early-pipeline processors (<code>MergeIntoOpenApi</code>, <code>MergeIntoComponents</code>, <code>DocBlockDescriptions</code>, <code>CleanUnmerged</code>)</li><li>Late-pipeline processors (<code>AugmentRefs</code>, <code>CleanUnusedComponents</code>)</li><li><code>Analysis::merged()</code> / <code>Analysis::unmerged()</code> / <code>Analysis::split()</code></li></ul><h3 id="context-annotations-array" tabindex="-1"><code>$context-&gt;annotations</code> (array) <a class="header-anchor" href="#context-annotations-array" aria-label="Permalink to &quot;`$context-&gt;annotations` (array)&quot;">​</a></h3><p>A per-source-location list of annotations declared at that context.</p><p><strong>Populated by:</strong> <code>Analysis::addAnnotation()</code>, which appends to the context&#39;s annotations array.</p><p><strong>Read by:</strong></p><ul><li><code>getAnnotationForSource()</code> — finds the source-declared annotation for a FQDN. Critical for <code>ExpandClasses</code>, <code>ExpandTraits</code>, <code>ExpandInterfaces</code>, <code>AugmentSchemas</code>, <code>AugmentDiscriminators</code>, and type resolvers.</li></ul><h2 id="the-annotation-tree" tabindex="-1">The Annotation Tree <a class="header-anchor" href="#the-annotation-tree" aria-label="Permalink to &quot;The Annotation Tree&quot;">​</a></h2><p>The annotation tree rooted at <code>$analysis-&gt;openapi</code> is the source of truth for what appears in the output. Annotations reachable from this root via non-blacklisted properties are serialized and validated.</p><h2 id="registry-completeness" tabindex="-1">Registry Completeness <a class="header-anchor" href="#registry-completeness" aria-label="Permalink to &quot;Registry Completeness&quot;">​</a></h2><p>The registries are <strong>complete</strong> — every annotation in the tree is also in the registry. This is guaranteed by the combination of:</p><ol><li><strong>Scanning phase:</strong> The analyser calls <code>addAnnotation()</code> on all discovered annotations, which recursively registers their children.</li><li><strong>Processing phase:</strong> Processors use <code>mergeAnnotations()</code> (or <code>addAnnotation()</code> directly) when creating or placing annotations, ensuring new annotations are always registered.</li></ol><p>Since <code>addAnnotation()</code> is <strong>idempotent</strong> (early-returns if the annotation already exists), calling it on already-registered annotations is a safe no-op. This eliminates the need for processors to track whether an annotation is &quot;new&quot; or &quot;already known.&quot;</p><h2 id="the-mergeannotations-method" tabindex="-1">The <code>mergeAnnotations</code> Method <a class="header-anchor" href="#the-mergeannotations-method" aria-label="Permalink to &quot;The `mergeAnnotations` Method&quot;">​</a></h2><h3 id="problem" tabindex="-1">Problem <a class="header-anchor" href="#problem" aria-label="Permalink to &quot;Problem&quot;">​</a></h3><p>Previously, processors that created new annotations needed two separate operations:</p><ol><li><code>$parent-&gt;merge([$annotation])</code> — place the annotation in the tree</li><li><code>$analysis-&gt;addAnnotation($annotation, ...)</code> — register it in the index</li></ol><p>This split was error-prone: some processors forgot step 2.</p><h3 id="solution" tabindex="-1">Solution <a class="header-anchor" href="#solution" aria-label="Permalink to &quot;Solution&quot;">​</a></h3><p><code>Analysis::mergeAnnotations($parent, $annotations, $ignore)</code> combines both:</p><ol><li>Calls <code>$parent-&gt;merge($annotations, $ignore)</code> to place annotations in the tree</li><li>Calls <code>addAnnotation()</code> for each annotation to ensure registration</li></ol><h3 id="when-to-use" tabindex="-1">When to use <a class="header-anchor" href="#when-to-use" aria-label="Permalink to &quot;When to use&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Situation</th><th>Method</th></tr></thead><tbody><tr><td>Processor merges annotations into a parent</td><td><code>$analysis-&gt;mergeAnnotations($parent, [...])</code></td></tr><tr><td>Processor creates an annotation and places it directly (not via merge)</td><td><code>$analysis-&gt;addAnnotation($annotation, $context)</code> + direct assignment</td></tr><tr><td>Processor relocates an annotation (removes from old parent, adds to new)</td><td><code>$analysis-&gt;removeAnnotation()</code> + direct assignment + <code>addAnnotation()</code></td></tr></tbody></table><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><ol><li><p>Processors must use <code>$analysis-&gt;mergeAnnotations()</code> when merging annotations into the tree. This guarantees registry completeness without requiring callers to remember a separate registration step.</p></li><li><p>The registries are complete and can be relied upon for type-based queries and ref scanning. Iterating <code>$analysis-&gt;annotations</code> is sufficient to find all annotations, including those created by processors.</p></li><li><p>Processors that need type-based queries should use <code>getAnnotationsOfType()</code> — it&#39;s correct and efficient.</p></li><li><p><code>AbstractAnnotation::merge()</code> should not be called directly by processors when <code>Analysis</code> is available. Direct <code>merge()</code> is acceptable only in contexts where annotations are already registered (e.g., trait methods operating on scan-time annotations without access to Analysis).</p></li></ol>',34)])])}const g=t(s,[["render",r]]);export{u as __pageData,g as default};
